(window.webpackJsonp=window.webpackJsonp||[]).push([[71],{543:function(t,e,n){"use strict";n.r(e);var r=n(0),o=Object(r.a)({},(function(){return this._self._c("ContentSlotsDistributor",{attrs:{"slot-key":this.$parent.slotKey}},[this._self._c("div",{domProps:{innerHTML:"<p>&lt;div class=&quot;custom-block tip&quot;&gt;&lt;p class=&quot;custom-block-title&quot;&gt;摘要&lt;/p&gt;\n在 3D 可视化项目中，模型加载是最基础也最关键的环节。本文基于实际项目经验，详细介绍 GLTFLoader 的使用技巧、Draco 压缩方案、加载进度管理以及大模型分片加载策略，帮助你在中小型 3D 场景中实现高效的模型加载体验。\n&lt;/div&gt;</p>\n<h2>一、为什么选择 GLTF 格式？</h2>\n<p>在 Three.js 生态中，支持的 3D 模型格式非常多：OBJ、FBX、GLTF、GLB 等。但 <strong>GLTF（GL Transmission Format）</strong> 已经成为事实上的标准，原因如下：</p>\n<ul>\n<li><strong>体积小</strong>：支持 Draco 压缩，模型体积可缩小 70%-90%</li>\n<li><strong>加载快</strong>：二进制格式 GLB 可以一次性加载所有资源</li>\n<li><strong>生态好</strong>：Blender、3ds Max 等主流建模软件均支持导出</li>\n<li><strong>信息完整</strong>：支持材质、动画、骨骼、灯光等完整场景信息</li>\n</ul>\n<h2>二、基础加载流程</h2>\n<pre><code class=\"language-javascript\">import * as THREE from 'three'\nimport { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader'\nimport { DRACOLoader } from 'three/examples/jsm/loaders/DRACOLoader'\n\n// 初始化 Draco 解码器\nconst dracoLoader = new DRACOLoader()\ndracoLoader.setDecoderPath('/draco/')\ndracoLoader.setDecoderConfig({ type: 'js' })\n\n// 初始化 GLTF 加载器\nconst gltfLoader = new GLTFLoader()\ngltfLoader.setDRACOLoader(dracoLoader)\n\n// 加载模型\ngltfLoader.load(\n  '/models/machine-room.glb',\n  (gltf) =&gt; {\n    const model = gltf.scene\n    model.traverse((child) =&gt; {\n      if (child.isMesh) {\n        child.castShadow = true\n        child.receiveShadow = true\n        // 优化材质\n        child.material.envMapIntensity = 1.5\n      }\n    })\n    scene.add(model)\n  },\n  (progress) =&gt; {\n    const percent = (progress.loaded / progress.total * 100).toFixed(1)\n    console.log(`加载进度: ${percent}%`)\n  },\n  (error) =&gt; {\n    console.error('模型加载失败:', error)\n  }\n)\n</code></pre>\n<h2>三、Draco 压缩实践</h2>\n<p>在我们的数字孪生机房项目中，原始 GLB 模型达到了 <strong>48MB</strong>，经过 Draco 压缩后降至 <strong>6.2MB</strong>，加载时间从 12s 降至 2.3s。</p>\n<h3>压缩命令</h3>\n<pre><code class=\"language-bash\"># 使用 gltf-pipeline 进行 Draco 压缩\nnpx gltf-pipeline -i input.glb -o output.glb -d --draco.compressionLevel 7\n</code></pre>\n<h3>注意事项</h3>\n<ol>\n<li><strong>Draco 解码器路径</strong>：需要将 <code>draco</code> 目录下的解码器文件复制到项目的 <code>public</code> 目录</li>\n<li><strong>首次解码延迟</strong>：Draco 解码器首次加载时需要初始化 WASM，建议在页面加载时预初始化</li>\n<li><strong>压缩级别选择</strong>：<code>compressionLevel</code> 范围 0-10，建议使用 7，兼顾压缩率与解码速度</li>\n</ol>\n<h2>四、加载管理器封装</h2>\n<p>在实际项目中，通常需要加载多个模型，我们封装了一个统一的加载管理器：</p>\n<pre><code class=\"language-javascript\">class ModelLoadManager {\n  constructor() {\n    this.loader = new GLTFLoader()\n    this.cache = new Map()\n    this.loadingQueue = []\n  }\n\n  async loadModel(url, options = {}) {\n    // 缓存命中\n    if (this.cache.has(url)) {\n      return this.cache.get(url).clone()\n    }\n\n    return new Promise((resolve, reject) =&gt; {\n      this.loader.load(\n        url,\n        (gltf) =&gt; {\n          const model = gltf.scene\n          // 预处理模型\n          this.preprocessModel(model, options)\n          // 缓存\n          this.cache.set(url, model)\n          resolve(model.clone())\n        },\n        options.onProgress,\n        reject\n      )\n    })\n  }\n\n  preprocessModel(model, options) {\n    model.traverse((child) =&gt; {\n      if (child.isMesh) {\n        // 开启阴影\n        if (options.shadow !== false) {\n          child.castShadow = true\n          child.receiveShadow = true\n        }\n        // 材质优化\n        if (child.material) {\n          child.material.needsUpdate = true\n        }\n      }\n    })\n  }\n\n  clearCache() {\n    this.cache.forEach((model) =&gt; {\n      model.traverse((child) =&gt; {\n        if (child.isMesh) {\n          child.geometry.dispose()\n          child.material.dispose()\n        }\n      })\n    })\n    this.cache.clear()\n  }\n}\n</code></pre>\n<h2>五、大场景分片加载策略</h2>\n<p>当场景包含 <strong>100+ 台设备</strong> 时，一次性加载所有模型会导致内存占用过高。我们采用了分片加载策略：</p>\n<ol>\n<li><strong>视距加载</strong>：根据摄像机距离，只加载可视范围内的设备模型</li>\n<li><strong>LOD 切换</strong>：远距离使用低精度模型，近距离切换高精度模型</li>\n<li><strong>实例化渲染</strong>：相同型号设备使用 <code>InstancedMesh</code> 减少 Draw Call</li>\n</ol>\n<pre><code class=\"language-javascript\">// InstancedMesh 示例 - 100台相同服务器\nconst serverGeometry = baseServer.geometry\nconst serverMaterial = baseServer.material\nconst instancedMesh = new THREE.InstancedMesh(serverGeometry, serverMaterial, 100)\n\nconst dummy = new THREE.Object3D()\nserverPositions.forEach((pos, i) =&gt; {\n  dummy.position.set(pos.x, pos.y, pos.z)\n  dummy.updateMatrix()\n  instancedMesh.setMatrixAt(i, dummy.matrix)\n})\n\nscene.add(instancedMesh)\n</code></pre>\n<h2>六、总结</h2>\n<table>\n<thead>\n<tr>\n<th>优化手段</th>\n<th>效果</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Draco 压缩</td>\n<td>模型体积减少 80%+</td>\n</tr>\n<tr>\n<td>模型缓存</td>\n<td>重复加载时间归零</td>\n</tr>\n<tr>\n<td>InstancedMesh</td>\n<td>Draw Call 减少 90%</td>\n</tr>\n<tr>\n<td>分片加载</td>\n<td>首屏内存占用降低 60%</td>\n</tr>\n</tbody>\n</table>\n<p>在实际的数字孪生项目中，这些优化手段组合使用，可以让包含上百台设备的 3D 机房场景在 <strong>3 秒内完成首屏加载</strong>，用户体验大幅提升。</p>\n"}})])}),[],!1,null,null,null);e.default=o.exports}}]);